const eventStore = yield* EventStore.Service
const sessionId = ctx.sessionID

let activePaths: string[] = []
let conflictFiles: string[] = []

try {
  const activeReservations = yield* Coordination.getSessionReservations(sessionId)
  if (activeReservations.length > 0) {
    activePaths = activeReservations.map((r) => r.path)
  } else {
    // Fallback: derive claim paths from recent events
    const recentEvents = yield* eventStore.query({
      sessionId,
      limit: 100,
      order: "desc",
    })
    activePaths = extractFilePaths(recentEvents)
  }
} catch (e) {
  // Fallback on error
  const recentEvents = yield* eventStore.query({
    sessionId,
    limit: 100,
    order: "desc",
  })
  activePaths = extractFilePaths(recentPaths)
}

return formatResult("Claim Context", {
  session_id: sessionId,
  active_claims: activePaths,
  total_claims: activePaths.length,
})

