function extractFilePaths(events: RuntimeEventType[]): string[] {
  const seen = new Set<string>()
  const result: string[] = []
  for (const ev of events) {
    if (ev.filePath && !seen.has(ev.filePath)) {
      seen.add(ev.filePath)
      result.push(ev.filePath)
    }
  }
  return result
}
